import{_ as t,I as n,o as s,c as l,j as i,a as o,J as r,aj as c}from"./chunks/framework.BEfmlIlB.js";const y=JSON.parse('{"title":"Managing Health Checks","description":"Enable or disable individual health checks via plugin configuration. Customize which checks run on your Joomla site.","frontmatter":{"description":"Enable or disable individual health checks via plugin configuration. Customize which checks run on your Joomla site.","head":[["meta",{"property":"og:title","content":"Managing Health Checks | Health Checker for Joomla"}],["meta",{"property":"og:description","content":"Enable or disable individual health checks via plugin configuration. Customize which checks run on your Joomla site."}],["meta",{"property":"og:url","content":"https://www.joomlahealthchecker.com/docs/guide/managing-checks"}],["meta",{"name":"twitter:title","content":"Managing Health Checks | Health Checker for Joomla"}],["meta",{"name":"twitter:description","content":"Enable or disable individual health checks via plugin configuration. Customize which checks run on your Joomla site."}],["meta",{"name":"twitter:url","content":"https://www.joomlahealthchecker.com/docs/guide/managing-checks"}]]},"headers":[],"relativePath":"guide/managing-checks.md","filePath":"guide/managing-checks.md"}'),h={name:"guide/managing-checks.md"};function d(g,e,u,p,k,m){const a=n("CopyOrDownloadAsMarkdownButtons");return s(),l("div",null,[e[0]||(e[0]=i("div",{style:{display:"none"},hidden:"true","aria-hidden":"true"},"Are you an LLM? You can read better optimized documentation at /docs/guide/managing-checks.md for this page in Markdown format",-1)),e[1]||(e[1]=i("h1",{id:"managing-health-checks",tabindex:"-1"},[o("Managing Health Checks "),i("a",{class:"header-anchor",href:"#managing-health-checks","aria-label":"Permalink to “Managing Health Checks”"},"​")],-1)),r(a),e[2]||(e[2]=c(`<p>Health Checker for Joomla allows you to enable or disable individual health checks through the plugin configuration interface. This gives you complete control over which checks run on your site.</p><h2 id="why-disable-checks" tabindex="-1">Why Disable Checks? <a class="header-anchor" href="#why-disable-checks" aria-label="Permalink to “Why Disable Checks?”">​</a></h2><p>You might want to disable certain checks if:</p><ul><li><strong>They&#39;re not relevant to your site</strong> - For example, if you don&#39;t use the JSON extension, you can disable that check</li><li><strong>They generate false positives</strong> - Some checks might flag warnings for configurations that are intentional on your site</li><li><strong>Performance optimization</strong> - Disabling unused checks reduces execution time</li><li><strong>Reducing noise</strong> - Focus on the checks that matter most to your specific setup</li></ul><h2 id="how-to-manage-checks" tabindex="-1">How to Manage Checks <a class="header-anchor" href="#how-to-manage-checks" aria-label="Permalink to “How to Manage Checks”">​</a></h2><h3 id="accessing-plugin-configuration" tabindex="-1">Accessing Plugin Configuration <a class="header-anchor" href="#accessing-plugin-configuration" aria-label="Permalink to “Accessing Plugin Configuration”">​</a></h3><ol><li>Log into your Joomla administrator panel</li><li>Navigate to <strong>Extensions → Plugins</strong></li><li>Search for <strong>&quot;Health Checker - Core Checks&quot;</strong></li><li>Click on the plugin name to edit it</li></ol><h3 id="understanding-the-configuration-screen" tabindex="-1">Understanding the Configuration Screen <a class="header-anchor" href="#understanding-the-configuration-screen" aria-label="Permalink to “Understanding the Configuration Screen”">​</a></h3><p>The plugin configuration is organized into 8 category fieldsets, matching the Health Checker categories:</p><ul><li><strong>Content Checks</strong> - Articles, categories, menus (11 checks)</li><li><strong>Database Checks</strong> - Connection, performance, integrity (17 checks)</li><li><strong>Extensions Checks</strong> - Joomla extensions and PHP extensions (21 checks)</li><li><strong>Performance Checks</strong> - Caching, compression, optimization (11 checks)</li><li><strong>Security Checks</strong> - SSL, permissions, authentication (22 checks)</li><li><strong>SEO Checks</strong> - Meta tags, URLs, sitemaps (11 checks)</li><li><strong>System &amp; Hosting Checks</strong> - PHP, server, resources (34 checks)</li><li><strong>Users Checks</strong> - Accounts, permissions, activity (12 checks)</li></ul><h3 id="disabling-individual-checks" tabindex="-1">Disabling Individual Checks <a class="header-anchor" href="#disabling-individual-checks" aria-label="Permalink to “Disabling Individual Checks”">​</a></h3><p>Each category has a list of checkboxes showing all available checks in that category:</p><ol><li><strong>Expand the category</strong> you want to configure (e.g., &quot;Extensions Checks&quot;)</li><li><strong>Uncheck the boxes</strong> for checks you want to disable <ul><li>For example, uncheck &quot;JSON Extension&quot; if you don&#39;t use it</li></ul></li><li><strong>Click Save &amp; Close</strong></li></ol><p>The next time you run Health Checker, the disabled checks will not execute.</p><h3 id="disabling-entire-categories" tabindex="-1">Disabling Entire Categories <a class="header-anchor" href="#disabling-entire-categories" aria-label="Permalink to “Disabling Entire Categories”">​</a></h3><p>To disable all checks in a category:</p><ol><li>Expand the category fieldset</li><li>Uncheck <strong>all</strong> the checkboxes in that category</li><li>Click Save &amp; Close</li></ol><blockquote><p><strong>Note:</strong> You cannot disable categories through the component itself - you must disable individual checks through the plugin configuration.</p></blockquote><h2 id="default-behavior" tabindex="-1">Default Behavior <a class="header-anchor" href="#default-behavior" aria-label="Permalink to “Default Behavior”">​</a></h2><p><strong>All checks are enabled by default</strong> when you first install Health Checker. You must explicitly disable checks you don&#39;t want to run.</p><p>If you haven&#39;t configured any checks:</p><ul><li>All 129 core checks will run</li><li>This is the recommended starting point for most sites</li><li>You can disable checks as needed after reviewing initial results</li></ul><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to “Examples”">​</a></h2><h3 id="example-1-disabling-php-extension-checks" tabindex="-1">Example 1: Disabling PHP Extension Checks <a class="header-anchor" href="#example-1-disabling-php-extension-checks" aria-label="Permalink to “Example 1: Disabling PHP Extension Checks”">​</a></h3><p>If your server doesn&#39;t have certain PHP extensions and you&#39;re okay with that:</p><ol><li>Go to plugin configuration</li><li>Expand <strong>&quot;Extensions Checks&quot;</strong></li><li>Uncheck: <ul><li>JSON Extension</li><li>Imagick Extension</li><li>EXIF Extension</li><li>(or any others you don&#39;t need)</li></ul></li><li>Save</li></ol><h3 id="example-2-disabling-content-checks" tabindex="-1">Example 2: Disabling Content Checks <a class="header-anchor" href="#example-2-disabling-content-checks" aria-label="Permalink to “Example 2: Disabling Content Checks”">​</a></h3><p>If you&#39;re running a simple site with minimal content management:</p><ol><li>Go to plugin configuration</li><li>Expand <strong>&quot;Content Checks&quot;</strong></li><li>Uncheck checks like: <ul><li>Orphaned Articles</li><li>Empty Articles</li><li>Draft Articles</li></ul></li><li>Save</li></ol><h3 id="example-3-focusing-only-on-security" tabindex="-1">Example 3: Focusing Only on Security <a class="header-anchor" href="#example-3-focusing-only-on-security" aria-label="Permalink to “Example 3: Focusing Only on Security”">​</a></h3><p>If you only care about security monitoring:</p><ol><li>Keep all <strong>&quot;Security Checks&quot;</strong> enabled</li><li>Disable checks in other categories as needed</li><li>This reduces execution time and focuses reports on security issues only</li></ol><h2 id="controlling-export-visibility" tabindex="-1">Controlling Export Visibility <a class="header-anchor" href="#controlling-export-visibility" aria-label="Permalink to “Controlling Export Visibility”">​</a></h2><p>Beyond enabling or disabling a check entirely, you can control whether each check appears in exported reports. This lets a check continue running and showing results in the admin UI while keeping it out of the reports you share with clients or hosting providers.</p><h3 id="how-to-configure-it" tabindex="-1">How to Configure It <a class="header-anchor" href="#how-to-configure-it" aria-label="Permalink to “How to Configure It”">​</a></h3><p>Each check in the plugin configuration has an <strong>Export Visibility</strong> dropdown alongside the enable/disable toggle:</p><ol><li>Go to <strong>Extensions → Plugins</strong> and open the plugin</li><li>Find the check you want to configure</li><li>Set the <strong>Export Visibility</strong> dropdown: <ul><li><strong>Always Export</strong> — included in every export (default for all checks)</li><li><strong>Issues Only</strong> — only included when the result is Warning or Critical</li><li><strong>Never Export</strong> — excluded from all exports</li></ul></li><li>Click <strong>Save &amp; Close</strong></li></ol><p>The check continues to run and its result is visible in the Health Checker dashboard. Only the export output is affected.</p><h3 id="example-preparing-a-client-report" tabindex="-1">Example: Preparing a Client Report <a class="header-anchor" href="#example-preparing-a-client-report" aria-label="Permalink to “Example: Preparing a Client Report”">​</a></h3><p>You manage a site for a client and want to send them an HTML report covering only application-level issues. Server configuration checks (PHP memory limits, MySQL settings) are things you handle on their behalf — there&#39;s no reason to include them in a client-facing report.</p><ol><li>Open the Core Checks plugin configuration</li><li>In the <strong>System &amp; Hosting Checks</strong> section, set the export visibility for server-level checks to <strong>Never Export</strong></li><li>Export the HTML report — it will contain only the checks relevant to the client</li></ol><h3 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to “Notes”">​</a></h3><ul><li>Export visibility has no effect on the admin dashboard — all enabled checks always appear there</li><li>The summary totals in an exported report (critical/warning/good counts) reflect only the checks that are included in that export</li><li>&quot;Issues Only&quot; is a good default for informational checks that rarely fail — the exported report stays focused on problems without losing those checks when they do trigger</li></ul><h2 id="impact-on-performance" tabindex="-1">Impact on Performance <a class="header-anchor" href="#impact-on-performance" aria-label="Permalink to “Impact on Performance”">​</a></h2><p>Disabled checks are <strong>completely skipped</strong> during execution:</p><ul><li>They don&#39;t run any code</li><li>They don&#39;t query the database</li><li>They don&#39;t appear in results</li><li>The total check count decreases</li></ul><p>This improves performance, especially if you disable many checks.</p><p><strong>Example:</strong> If you disable 20 checks out of 129, the health check will execute faster because those 20 checks are never instantiated or executed.</p><h2 id="dashboard-module" tabindex="-1">Dashboard Module <a class="header-anchor" href="#dashboard-module" aria-label="Permalink to “Dashboard Module”">​</a></h2><p>The <a href="/docs/dashboard-widget">Dashboard Module</a> automatically respects disabled checks:</p><ul><li>Only enabled checks appear in the widget</li><li>Counts and status badges reflect only active checks</li><li>Cache is based on enabled checks only</li></ul><h2 id="re-enabling-checks" tabindex="-1">Re-Enabling Checks <a class="header-anchor" href="#re-enabling-checks" aria-label="Permalink to “Re-Enabling Checks”">​</a></h2><p>To re-enable a previously disabled check:</p><ol><li>Return to the plugin configuration</li><li>Expand the relevant category</li><li><strong>Check the box</strong> next to the check you want to enable</li><li>Click Save &amp; Close</li></ol><p>The check will appear in results on the next health check run.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to “Troubleshooting”">​</a></h2><h3 id="check-titles-showing-as-language-keys" tabindex="-1">Check titles showing as language keys <a class="header-anchor" href="#check-titles-showing-as-language-keys" aria-label="Permalink to “Check titles showing as language keys”">​</a></h3><p>If you see <code>PLG_HEALTHCHECKER_CORE_CHECK_...</code> instead of check names:</p><ul><li>This is a language file issue, not a configuration issue</li><li>Reinstall the plugin to restore language files</li><li>Or manually add missing language keys to <code>plg_healthchecker_core.ini</code></li></ul><h3 id="all-checks-disabled-accidentally" tabindex="-1">All checks disabled accidentally <a class="header-anchor" href="#all-checks-disabled-accidentally" aria-label="Permalink to “All checks disabled accidentally”">​</a></h3><p>If you&#39;ve disabled too many checks and want to reset:</p><ol><li>Go to plugin configuration</li><li>Expand each category</li><li><strong>Check all boxes</strong> to re-enable everything</li><li>Or uninstall and reinstall the plugin to reset to defaults</li></ol><h3 id="changes-not-taking-effect" tabindex="-1">Changes not taking effect <a class="header-anchor" href="#changes-not-taking-effect" aria-label="Permalink to “Changes not taking effect”">​</a></h3><p>If disabling checks doesn&#39;t work:</p><ol><li>Verify you clicked <strong>Save &amp; Close</strong></li><li>Clear Joomla cache (System → Clear Cache)</li><li>Run health check again</li><li>Check that the plugin is <strong>enabled</strong> (not just configured)</li></ol><h2 id="advanced-plugin-parameters-in-database" tabindex="-1">Advanced: Plugin Parameters in Database <a class="header-anchor" href="#advanced-plugin-parameters-in-database" aria-label="Permalink to “Advanced: Plugin Parameters in Database”">​</a></h2><p>Disabled checks are stored as JSON arrays in the plugin parameters. For example:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;enabled_system&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;system.php_version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;system.disk_space&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;enabled_database&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;database.connection&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">  ...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>If a category parameter is empty or not set, <strong>all checks in that category are enabled by default</strong>.</p><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to “Best Practices”">​</a></h2><p>✅ <strong>DO:</strong></p><ul><li>Start with all checks enabled to get a baseline</li><li>Disable checks after understanding what they do</li><li>Disable checks that genuinely don&#39;t apply to your site</li><li>Document which checks you&#39;ve disabled and why</li></ul><p>❌ <strong>DON&#39;T:</strong></p><ul><li>Disable security checks just because they show warnings</li><li>Disable checks without understanding them first</li><li>Disable too many checks - you might miss important issues</li></ul><h2 id="related-documentation" tabindex="-1">Related Documentation <a class="header-anchor" href="#related-documentation" aria-label="Permalink to “Related Documentation”">​</a></h2><ul><li><a href="/docs/reading-results">Understanding Results</a> - Learn what each check means</li><li><a href="/docs/checks/">Check Reference</a> - Complete list of all checks</li><li><a href="/docs/getting-started">Getting Started</a> - Initial setup guide</li><li><a href="/docs/dashboard-widget">Dashboard Module</a> - Widget configuration</li></ul>`,76))])}const f=t(h,[["render",d]]);export{y as __pageData,f as default};
